use std::collections::HashMap;

fn solve(points: Vec<Vec<i64>>) -> i64 {
    const MOD: i64 = 1_000_000_007;
    let mut y_to_xs: HashMap<i64, Vec<i64>> = HashMap::new();

    for point in points {
        let x = point[0];
        let y = point[1];
        y_to_xs.entry(y).or_insert_with(Vec::new).push(x);
    }

    // Sort the x coordinates for each y
    for xs in y_to_xs.values_mut() {
        xs.sort();
    }

    // Collect and sort all unique y values
    let mut ys: Vec<i64> = y_to_xs.keys().cloned().collect();
    ys.sort();
    let n = ys.len();

    let mut total = 0;

    for i in 0..n {
        let y1 = ys[i];
        let m1 = y_to_xs[&y1].len();
        if m1 < 2 {
            continue;
        }
        for j in i+1..n {
            let y2 = ys[j];
            let m2 = y_to_xs[&y2].len();
            if m2 < 2 {
                continue;
            }
            let c = (m1 * (m1 - 1) / 2) as i64 * (m2 * (m2 - 1) / 2) as i64;
            total = (total + c) % MOD;
        }
    }

    total
}
